on pg *
{
  long err;
  dword checksum;
  dword counter;
  switch(this.pgn)
  {
    case 0xF123: //DCDC4OS
      err = J1939GetChecksumAndCounter (this, "Aa", checksum, counter);
      if(err != 0)
      {
        write("Invalid calculation method");
      }
      write("Checksum: %d", checksum);
      write("Message Counter: %d", counter);
      break;
    default:
      break;
  }
}
